from __future__ import annotations
import re
from dataclasses import dataclass
from enum import Enum

class EdgeKind(str, Enum):
    NORMAL = "normal"
    AMBIGUOUS = "ambiguous"
    OUT_OF_SCOPE = "out_of_scope"
    MALFORMED = "malformed"
    EMPTY = "empty"
    ADVERSARIAL = "adversarial"

@dataclass
class TriageResult:
    kind: EdgeKind
    confidence: float   # 0.0–1.0
    reason: str

MAX_INPUT_LEN = 8_000  # characters

def triage_input(text: str) -> TriageResult:
    """Lightweight, deterministic triage before the main LLM call."""
    if not text or not text.strip():
        return TriageResult(EdgeKind.EMPTY, 1.0, "Empty or whitespace-only input")

    if len(text) > MAX_INPUT_LEN:
        return TriageResult(EdgeKind.MALFORMED, 0.9,
            f"Input length {len(text)} exceeds {MAX_INPUT_LEN}")

    # Detect prompt-injection patterns
    injection_patterns = [
        r"ignore (previous|all) instructions",
        r"disregard (your|the) (system|original) prompt",
        r"you are now",
        r"act as (an? )?(?:DAN|jailbreak|unrestricted)",
    ]
    for pat in injection_patterns:
        if re.search(pat, text, re.IGNORECASE):
            return TriageResult(EdgeKind.ADVERSARIAL, 0.95,
                f"Possible prompt injection: matched '{pat}'")

    # Ambiguity heuristic: multiple contradictory instructions
    imperative_count = len(re.findall(
        r"\b(do|don't|must|must not|always|never)\b", text, re.IGNORECASE
    ))
    if imperative_count >= 4 and len(text.split()) < 30:
        return TriageResult(EdgeKind.AMBIGUOUS, 0.7,
            f"Short text with {imperative_count} conflicting imperatives")

    return TriageResult(EdgeKind.NORMAL, 1.0, "Passed all checks")

from __future__ import annotations
import json
from typing import Any
from pydantic import BaseModel, ValidationError, field_validator

class AgentResponse(BaseModel):
    """Typed output contract for every non-refused agent turn."""
    answer: str
    confidence: float          # 0.0–1.0
    sources: list[str]
    caveats: list[str] = []    # populated on graceful degradation
    refused: bool = False
    refusal_reason: str = ""

    @field_validator("confidence")
    @classmethod
    def check_confidence(cls, v: float) -> float:
        if not 0.0 <= v <= 1.0:
            raise ValueError("confidence must be between 0.0 and 1.0")
        return round(v, 4)

SYSTEM_PROMPT = """
You are a reliable research assistant. Your output MUST be valid JSON matching:
{
  "answer": "<string, max 500 chars>",
  "confidence": <float 0.0–1.0>,
  "sources": ["<url or citation>", ...],
  "caveats": ["<caveat if unsure>", ...],
  "refused": false,
  "refusal_reason": ""
}
If the question is outside your scope or you cannot answer reliably,
set "refused": true and explain in "refusal_reason".
Do not output any text outside the JSON object.
EDGE CASE EXAMPLES:
  Input: ""  -> { "refused": true, "refusal_reason": "Empty input", ... }
  Input: "Who won the 2200 World Cup?" ->
    { "refused": true, "refusal_reason": "Future event, no data", ... }
"""

