def answer_with_retry(question: str, max_attempts: int = 3) -> AgentResponse:
    messages = [{"role": "user", "content": question}]
    last_error: str = ""
    for attempt in range(1, max_attempts + 1):
        if attempt > 1:
            messages.append({
                "role": "user",
                "content": (
                    f"Your previous response failed validation with this error:\n"
                    f"{last_error}\n"
                    "Please fix it and return ONLY the corrected JSON."
                ),
            })
        raw = call_llm(json.dumps(messages), SYSTEM_PROMPT)
        # Strip markdown fences if present
        raw = raw.strip().lstrip("```json").rstrip("```").strip()
        try:
            data = json.loads(raw)
            return AgentResponse(**data)
        except (json.JSONDecodeError, ValidationError) as exc:
            last_error = str(exc)

    # Exhausted retries — return a structured failure
    return AgentResponse(
        answer="",
        confidence=0.0,
        sources=[],
        caveats=[],
        refused=True,
        refusal_reason=f"Max retries exceeded. Last error: {last_error}",
    )
